using Expenses.Domain; using Microsoft.EntityFrameworkCore; using Microsoft.EntityFrameworkCore.Metadata.Builders;
namespace Expenses.Persistence; /** <summary>Expense mapping.</summary> */ public sealed class ExpenseConfiguration:IEntityTypeConfiguration<Expense>{/** <inheritdoc/> */ public void Configure(EntityTypeBuilder<Expense> b){b.ToTable("expenses");b.HasKey(x=>x.Id);b.Property(x=>x.Category).HasMaxLength(100).IsRequired();b.Property(x=>x.Amount).HasPrecision(18,2);b.Property(x=>x.Payee).HasMaxLength(200).IsRequired();b.Property(x=>x.Notes).HasMaxLength(2000);b.HasIndex(x=>x.Date);b.HasIndex(x=>x.Category);}}
